#include<bits/stdc++.h>
using namespace std;
int k,n,m;
struct node{
	int c,l;//c->come,l->leave
}in[100005],out[100005];
bool cmp(node x,node y){
	return x.c<y.c;
}
int check(int i,int o){
	int cnt = 0;
	queue<node>in_q,out_q;
	if(i != 0){
		for(int j = 0; j < n; j++){
			while(in_q.size()){
				auto w = in_q.front();
				if(w.l < in[j].c){
					in_q.pop();
					i++;
				}else{
					break;
				}
			}
			if(i > 0){
				in_q.push(in[j]);
//				cout << in[j].c << " " << in[j].l << endl;
				cnt++;
				i--;
			}
		}
	}
	if(o != 0){
		for(int j = 0; j < m; j++){
			while(out_q.size()){
				auto w = out_q.front();
				if(w.l < in[j].c){
					out_q.pop();
					o++;
				}else{
					break;
				}
			}
			if(o > 0){
				out_q.push(in[j]);
//				cout << out[j].c << " " << out[j].l << endl;
				cnt++;
				o--;
			}
		}
	}
	return cnt;
}
int main()
{
	cin>>k>>n>>m;
	for(int i = 0; i < n; i++){
		cin >> in[i].c >> in[i].l;
	}
	for(int i = 0; i < m; i++){
		cin >> out[i].c >> out[i].l;
	}
	sort(in,in+n,cmp);
	sort(out,out+m,cmp);
	int maxi = 0;
	for(int i = 0, o = k;i <= k && o >= 0; i++,o--){
//		cout<<endl;
		int x=check(i,o);
		maxi = max(maxi,x);
	}
	cout<<maxi;
}
